@import url('https://fonts.googleapis.com/css2?family=Lato:wght@300;400;700&family=Playfair+Display:wght@400;700&display=swap');

:root {
  --color-bg: #0f0f0f;
  --color-bg-secondary: #1a1a1a;
  --color-gold-primary: #d4af37;
  --color-gold-light: #f1d47f;
  --color-gold-dark: #aa8c2c;
  --color-text-main: #ffffff;
  --color-text-muted: #cccccc;
  --font-heading: 'Playfair Display', serif;
  --font-body: 'Lato', sans-serif;
  --spacing-unit: 1rem;
  --border-radius: 8px;
  --transition-speed: 0.3s;
  --container-width: 1200px;
}

/* Reset & Base */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  background-color: var(--color-bg);
  color: var(--color-text-main);
  font-family: var(--font-body);
  line-height: 1.6;
  overflow-x: hidden;
}

h1, h2, h3, h4 {
  font-family: var(--font-heading);
  color: var(--color-gold-primary);
  margin-bottom: var(--spacing-unit);
  font-weight: 700;
}

p {
  margin-bottom: 1rem;
  color: var(--color-text-muted);
}

a {
  text-decoration: none;
  color: inherit;
  transition: color var(--transition-speed);
}

a:hover {
  color: var(--color-gold-light);
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

/* Utilities */
.container {
  max-width: var(--container-width);
  margin: 0 auto;
  padding: 0 20px;
}

.section-padding {
  padding: 80px 0;
}

.text-center {
  text-align: center;
}

.section-title {
  font-size: 2.5rem;
  margin-bottom: 10px;
  background: linear-gradient(to right, var(--color-gold-light), var(--color-gold-primary));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  display: inline-block;
}

.section-subtitle {
  color: var(--color-text-muted);
  margin-bottom: 50px;
  font-size: 1.1rem;
}

/* Animations */
@keyframes fadeIn {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes goldShimmer {
  0% { background-position: -200%; }
  100% { background-position: 200%; }
}

@keyframes float {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-10px); }
}

.animate-fade-in {
  animation: fadeIn 1s ease-out forwards;
}

/* Buttons */
.btn {
  display: inline-block;
  padding: 12px 30px;
  background: linear-gradient(45deg, var(--color-gold-dark), var(--color-gold-primary), var(--color-gold-light), var(--color-gold-primary));
  background-size: 300% 300%;
  color: var(--color-bg);
  font-weight: bold;
  border-radius: 50px;
  border: none;
  cursor: pointer;
  transition: all var(--transition-speed);
  animation: goldShimmer 3s infinite linear;
  font-family: var(--font-body);
  text-transform: uppercase;
  letter-spacing: 1px;
  font-size: 0.9rem;
}

.btn:hover {
  transform: scale(1.05);
  box-shadow: 0 0 20px rgba(212, 175, 55, 0.5);
  color: #000;
}

/* Hero Section */
.hero {
  height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: radial-gradient(circle at center, #2a2a2a 0%, var(--color-bg) 100%);
  position: relative;
  overflow: hidden;
}

.hero::before {
  content: '';
  position: absolute;
  width: 200%;
  height: 200%;
  background: radial-gradient(circle, rgba(212, 175, 55, 0.1) 0%, transparent 60%);
  animation: float 10s infinite ease-in-out;
  z-index: 1;
}

.hero-content {
  text-align: center;
  z-index: 2;
  padding: 0 20px;
}

.hero h1 {
  font-size: 4rem;
  text-transform: uppercase;
  letter-spacing: 3px;
  background: linear-gradient(to right, var(--color-gold-light), var(--color-gold-primary), var(--color-gold-light));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  margin-bottom: 20px;
  line-height: 1.2;
}

.hero p {
  font-size: 1.25rem;
  color: var(--color-text-muted);
  max-width: 600px;
  margin: 0 auto 30px;
}

/* Awards Section */
.awards {
  background-color: var(--color-bg-secondary);
  position: relative;
}

.awards-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 30px;
  margin-top: 40px;
}

.award-card {
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(212, 175, 55, 0.3);
  border-radius: var(--border-radius);
  padding: 40px 30px;
  text-align: center;
  transition: all var(--transition-speed);
  position: relative;
  overflow: hidden;
  backdrop-filter: blur(5px);
}

.award-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 3px;
  background: linear-gradient(90deg, transparent, var(--color-gold-primary), transparent);
  transform: scaleX(0);
  transition: transform var(--transition-speed);
}

.award-card:hover::before {
  transform: scaleX(1);
}

.award-card:hover {
  transform: translateY(-10px);
  border-color: var(--color-gold-primary);
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.5);
  background: rgba(255, 255, 255, 0.05);
}

.award-icon {
  font-size: 3.5rem;
  color: var(--color-gold-primary);
  margin-bottom: 20px;
  animation: float 3s ease-in-out infinite;
  display: inline-block;
}

.award-card h3 {
  font-size: 1.5rem;
  color: var(--color-text-main);
  margin-bottom: 10px;
}

.award-card p {
  color: var(--color-text-muted);
  font-size: 0.95rem;
  margin-bottom: 0;
}

.award-year {
  display: inline-block;
  margin-top: 15px;
  padding: 4px 12px;
  border: 1px solid var(--color-gold-dark);
  border-radius: 20px;
  font-size: 0.8rem;
  color: var(--color-gold-light);
}

/* Projects Section */
.projects {
  background-color: var(--color-bg);
}

.projects-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 30px;
  margin-top: 40px;
}

.project-card {
  background: var(--color-bg-secondary);
  border-radius: var(--border-radius);
  overflow: hidden;
  transition: transform var(--transition-speed);
  border: 1px solid transparent;
  position: relative;
}

.project-card:hover {
  transform: scale(1.02);
  border-color: var(--color-gold-dark);
}

.project-image {
  width: 100%;
  height: 220px;
  background-color: #333;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--color-gold-primary);
  font-size: 3rem;
  position: relative;
  overflow: hidden;
}

.project-image::after {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: linear-gradient(to bottom, transparent, rgba(0,0,0,0.8));
}

.project-info {
  padding: 25px;
  position: relative;
  z-index: 2;
}

.project-info h3 {
  font-size: 1.4rem;
  color: var(--color-gold-light);
  margin-bottom: 10px;
}

.project-info p {
  font-size: 0.9rem;
  margin-bottom: 20px;
}

.project-link {
  color: var(--color-gold-primary);
  font-weight: bold;
  font-size: 0.9rem;
  text-transform: uppercase;
  letter-spacing: 1px;
}

.project-link:hover {
  color: var(--color-gold-light);
  text-decoration: underline;
}

/* Contact Section */
.contact {
  background: linear-gradient(to bottom, var(--color-bg-secondary), var(--color-bg));
}

.contact-form {
  max-width: 600px;
  margin: 40px auto 0;
  background: rgba(255, 255, 255, 0.03);
  padding: 40px;
  border-radius: var(--border-radius);
  border: 1px solid rgba(212, 175, 55, 0.2);
  box-shadow: 0 10px 30px rgba(0,0,0,0.3);
}

.form-group {
  margin-bottom: 20px;
}

.form-group label {
  display: block;
  margin-bottom: 8px;
  color: var(--color-gold-primary);
  font-weight: bold;
  font-size: 0.9rem;
  text-transform: uppercase;
  letter-spacing: 1px;
}

.form-group input,
.form-group textarea {
  width: 100%;
  padding: 15px;
  background: rgba(0, 0, 0, 0.3);
  border: 1px solid #333;
  border-radius: 4px;
  color: var(--color-text-main);
  font-family: var(--font-body);
  font-size: 1rem;
  transition: border-color var(--transition-speed), box-shadow var(--transition-speed);
}

.form-group input:focus,
.form-group textarea:focus {
  outline: none;
  border-color: var(--color-gold-primary);
  box-shadow: 0 0 10px rgba(212, 175, 55, 0.2);
}

.form-group textarea {
  resize: vertical;
  min-height: 150px;
}

/* Footer */
footer {
  background-color: #000;
  padding: 40px 0;
  text-align: center;
  border-top: 1px solid rgba(212, 175, 55, 0.3);
}

footer p {
  color: var(--color-text-muted);
  font-size: 0.9rem;
  margin-bottom: 0;
}

.social-links {
  margin-bottom: 20px;
}

.social-links a {
  margin: 0 10px;
  font-size: 1.2rem;
  color: var(--color-gold-primary);
}

/* Responsive Design */
@media (max-width: 992px) {
  .hero h1 {
    font-size: 3rem;
  }

  .section-title {
    font-size: 2rem;
  }
}

@media (max-width: 768px) {
  .hero h1 {
    font-size: 2.5rem;
  }

  .section-padding {
    padding: 50px 0;
  }

  .awards-grid,
  .projects-grid {
    grid-template-columns: 1fr;
  }

  .contact-form {
    padding: 25px;
  }

  .hero-content {
    padding: 0 15px;
  }
}

@media (max-width: 480px) {
  .hero h1 {
    font-size: 2rem;
  }

  .btn {
    width: 100%;
    text-align: center;
    padding: 15px 30px;
  }

  .award-card {
    padding: 30px 20px;
  }

  .section-title {
    font-size: 1.75rem;
  }
}

