// Hero Section Component with Typing Animation and CTA Buttons

export function initHero() {
  const heroRoot = document.getElementById('hero-root');

  if (!heroRoot) {
    console.error('Hero root element not found');
    return;
  }

  // Hero content data
  const heroData = {
    title: 'Creative Developer',
    subtitle: 'Building Digital Experiences That Inspire',
    description: 'I craft elegant solutions and stunning interfaces that blend art with technology. Let\'s create something extraordinary together.',
    ctaButtons: [
      { text: 'View Projects', href: '#projects', primary: true },
      { text: 'Contact Me', href: '#contact', primary: false }
    ]
  };

  // Create hero HTML structure
  heroRoot.innerHTML = `
    <div class="hero">
      <div class="hero-content">
        <h1 class="hero-title">
          <span class="typing-text"></span><span class="cursor">|</span>
        </h1>
        <p class="hero-subtitle animate-fade-in" style="animation-delay: 0.5s">${heroData.subtitle}</p>
        <p class="hero-description animate-fade-in" style="animation-delay: 0.8s">${heroData.description}</p>
        <div class="hero-cta animate-fade-in" style="animation-delay: 1.1s">
          ${heroData.ctaButtons.map(btn => `
            <a href="${btn.href}" class="btn ${btn.primary ? 'btn-primary' : 'btn-secondary'}">
              ${btn.text}
            </a>
          `).join('')}
        </div>
      </div>
    </div>
  `;

  // Typing animation
  const typingElement = heroRoot.querySelector('.typing-text');
  const cursorElement = heroRoot.querySelector('.cursor');
  const titleText = heroData.title;
  let charIndex = 0;

  function typeWriter() {
    if (charIndex < titleText.length) {
      typingElement.textContent += titleText.charAt(charIndex);
      charIndex++;
      setTimeout(typeWriter, 100);
    } else {
      // Stop cursor blinking after typing completes
      setTimeout(() => {
        cursorElement.style.animation = 'none';
        cursorElement.style.opacity = '0';
      }, 2000);
    }
  }

  // Add cursor blink animation styles
  const style = document.createElement('style');
  style.textContent = `
    .cursor {
      color: var(--color-gold-primary);
      animation: blink 1s infinite;
    }

    @keyframes blink {
      0%, 50% { opacity: 1; }
      51%, 100% { opacity: 0; }
    }

    .hero-cta {
      display: flex;
      gap: 20px;
      justify-content: center;
      flex-wrap: wrap;
      margin-top: 30px;
    }

    .btn-secondary {
      background: transparent;
      border: 2px solid var(--color-gold-primary);
      color: var(--color-gold-primary);
      animation: none;
    }

    .btn-secondary:hover {
      background: var(--color-gold-primary);
      color: var(--color-bg);
      box-shadow: 0 0 20px rgba(212, 175, 55, 0.5);
    }

    .hero-title {
      min-height: 4.8rem;
    }
  `;
  document.head.appendChild(style);

  // Start typing animation after a brief delay
  setTimeout(typeWriter, 500);

  // Add smooth scroll for CTA buttons
  heroRoot.querySelectorAll('a[href^="#"]').forEach(anchor => {
    anchor.addEventListener('click', function(e) {
      e.preventDefault();
      const targetId = this.getAttribute('href');
      const targetSection = document.querySelector(targetId);
      if (targetSection) {
        targetSection.scrollIntoView({ behavior: 'smooth' });
      }
    });
  });
}

