/* src/styles.css - Comprehensive Responsive Styles */

/* CSS Variables */
:root {
  --color-bg: #0a0a0f;
  --color-bg-secondary: #12121a;
  --color-text: #e0e0e0;
  --color-text-muted: #a0a0a0;
  --color-gold-primary: #d4af37;
  --color-gold-secondary: #b8942e;
  --color-gold-light: #f4d06f;
  --color-accent: #c9a227;
  --font-primary: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  --font-heading: 'Playfair Display', Georgia, serif;
  --spacing-xs: 0.5rem;
  --spacing-sm: 1rem;
  --spacing-md: 1.5rem;
  --spacing-lg: 2rem;
  --spacing-xl: 3rem;
  --spacing-2xl: 4rem;
  --border-radius-sm: 4px;
  --border-radius-md: 8px;
  --border-radius-lg: 12px;
  --transition-fast: 0.2s ease;
  --transition-normal: 0.3s ease;
  --transition-slow: 0.5s ease;
  --shadow-sm: 0 2px 8px rgba(0, 0, 0, 0.3);
  --shadow-md: 0 4px 16px rgba(0, 0, 0, 0.4);
  --shadow-lg: 0 10px 30px rgba(0, 0, 0, 0.5);
  --shadow-gold: 0 5px 20px rgba(212, 175, 55, 0.3);
}

/* Reset & Base Styles */
*, *::before, *::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
  font-size: 16px;
}

body {
  font-family: var(--font-primary);
  background: var(--color-bg);
  color: var(--color-text);
  line-height: 1.6;
  overflow-x: hidden;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: var(--color-gold-primary);
  text-decoration: none;
  transition: color var(--transition-fast);
}

a:hover {
  color: var(--color-gold-light);
}

button {
  font-family: inherit;
  cursor: pointer;
  border: none;
  background: none;
}

/* Container */
.container {
  width: 100%;
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 var(--spacing-md);
}

/* Typography */
h1, h2, h3, h4, h5, h6 {
  font-family: var(--font-heading);
  font-weight: 700;
  line-height: 1.2;
  color: var(--color-gold-primary);
}

h1 {
  font-size: clamp(2.5rem, 5vw, 4rem);
  margin-bottom: var(--spacing-md);
}

h2 {
  font-size: clamp(2rem, 4vw, 3rem);
  margin-bottom: var(--spacing-md);
}

h3 {
  font-size: clamp(1.5rem, 3vw, 2rem);
  margin-bottom: var(--spacing-sm);
}

p {
  margin-bottom: var(--spacing-sm);
  color: var(--color-text);
}

/* Section Styles */
section {
  padding: var(--spacing-2xl) 0;
}

.section-title {
  text-align: center;
  margin-bottom: var(--spacing-lg);
}

.section-subtitle {
  text-align: center;
  color: var(--color-text-muted);
  font-size: clamp(1rem, 2vw, 1.2rem);
  max-width: 600px;
  margin: 0 auto var(--spacing-xl);
}

/* Buttons */
.btn {
  display: inline-block;
  padding: var(--spacing-sm) var(--spacing-lg);
  background: var(--color-gold-primary);
  color: var(--color-bg);
  font-weight: 600;
  font-size: 1rem;
  border-radius: var(--border-radius-md);
  transition: all var(--transition-normal);
  text-transform: uppercase;
  letter-spacing: 1px;
  min-height: 48px;
  min-width: 48px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.btn:hover {
  background: var(--color-gold-secondary);
  transform: translateY(-2px);
  box-shadow: var(--shadow-gold);
  color: var(--color-bg);
}

.btn-secondary {
  background: transparent;
  border: 2px solid var(--color-gold-primary);
  color: var(--color-gold-primary);
}

.btn-secondary:hover {
  background: var(--color-gold-primary);
  color: var(--color-bg);
}

/* Hero Section */
.hero {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
  padding: var(--spacing-2xl) 0;
  overflow: hidden;
}

.hero::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: radial-gradient(circle at 50% 50%, rgba(212, 175, 55, 0.1) 0%, transparent 70%);
  pointer-events: none;
}

.hero-content {
  text-align: center;
  z-index: 1;
  padding: var(--spacing-lg);
}

.hero-title {
  font-size: clamp(2.5rem, 8vw, 5rem);
  margin-bottom: var(--spacing-md);
  animation: fadeIn 1s ease-out;
}

.hero-subtitle {
  font-size: clamp(1.1rem, 3vw, 1.5rem);
  color: var(--color-text-muted);
  margin-bottom: var(--spacing-xl);
  max-width: 600px;
  margin-left: auto;
  margin-right: auto;
  animation: fadeIn 1s ease-out 0.3s backwards;
}

.hero-buttons {
  display: flex;
  gap: var(--spacing-md);
  justify-content: center;
  flex-wrap: wrap;
  animation: fadeIn 1s ease-out 0.6s backwards;
}

.hero-buttons .btn {
  min-width: 160px;
}

/* Scroll Indicator */
.scroll-indicator {
  position: absolute;
  bottom: var(--spacing-xl);
  left: 50%;
  transform: translateX(-50%);
  animation: bounce 2s infinite;
}

.scroll-indicator span {
  display: block;
  width: 30px;
  height: 50px;
  border: 2px solid var(--color-gold-primary);
  border-radius: 15px;
  position: relative;
}

.scroll-indicator span::before {
  content: '';
  position: absolute;
  top: 8px;
  left: 50%;
  transform: translateX(-50%);
  width: 6px;
  height: 10px;
  background: var(--color-gold-primary);
  border-radius: 3px;
  animation: scroll 2s infinite;
}

@keyframes bounce {
  0%, 20%, 50%, 80%, 100% {
    transform: translateX(-50%) translateY(0);
  }
  40% {
    transform: translateX(-50%) translateY(-10px);
  }
  60% {
    transform: translateX(-50%) translateY(-5px);
  }
}

@keyframes scroll {
  0% {
    opacity: 1;
    transform: translateX(-50%) translateY(0);
  }
  100% {
    opacity: 0;
    transform: translateX(-50%) translateY(20px);
  }
}

/* Projects Section */
.projects-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: var(--spacing-lg);
  margin-top: var(--spacing-xl);
}

.project-card {
  background: var(--color-bg-secondary);
  border-radius: var(--border-radius-lg);
  overflow: hidden;
  transition: all var(--transition-normal);
  box-shadow: var(--shadow-md);
}

.project-card:hover {
  transform: translateY(-10px);
  box-shadow: var(--shadow-gold);
}

.project-image {
  width: 100%;
  height: 200px;
  object-fit: cover;
  transition: transform var(--transition-slow);
}

.project-card:hover .project-image {
  transform: scale(1.05);
}

.project-content {
  padding: var(--spacing-lg);
}

.project-title {
  font-size: 1.5rem;
  margin-bottom: var(--spacing-sm);
}

.project-description {
  color: var(--color-text-muted);
  margin-bottom: var(--spacing-md);
  font-size: 0.95rem;
}

.project-tags {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-xs);
  margin-bottom: var(--spacing-md);
}

.project-tag {
  background: rgba(212, 175, 55, 0.1);
  color: var(--color-gold-primary);
  padding: 4px 12px;
  border-radius: 20px;
  font-size: 0.85rem;
}

.project-links {
  display: flex;
  gap: var(--spacing-sm);
}

.project-links a {
  font-size: 0.9rem;
  padding: var(--spacing-xs) var(--spacing-sm);
}

/* Awards Section */
.awards-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: var(--spacing-lg);
  margin-top: var(--spacing-xl);
}

.award-card {
  background: var(--color-bg-secondary);
  border-radius: var(--border-radius-lg);
  padding: var(--spacing-lg);
  text-align: center;
  transition: all var(--transition-normal);
  box-shadow: var(--shadow-md);
  border: 1px solid rgba(212, 175, 55, 0.1);
}

.award-card:hover {
  transform: translateY(-10px);
  border-color: var(--color-gold-primary);
  box-shadow: var(--shadow-gold);
}

.award-icon {
  font-size: 3rem;
  margin-bottom: var(--spacing-md);
  color: var(--color-gold-primary);
}

.award-title {
  font-size: 1.3rem;
  margin-bottom: var(--spacing-xs);
}

.award-organization {
  color: var(--color-text-muted);
  font-size: 0.95rem;
  margin-bottom: var(--spacing-sm);
}

.award-year {
  background: rgba(212, 175, 55, 0.2);
  color: var(--color-gold-primary);
  padding: 4px 12px;
  border-radius: 20px;
  font-size: 0.85rem;
  display: inline-block;
}

/* Contact Section */
.contact-content {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--spacing-2xl);
  align-items: start;
}

.contact-info {
  padding: var(--spacing-lg);
}

.contact-item {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
  margin-bottom: var(--spacing-lg);
}

.contact-icon {
  width: 50px;
  height: 50px;
  background: rgba(212, 175, 55, 0.1);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--color-gold-primary);
  font-size: 1.2rem;
  flex-shrink: 0;
}

.contact-text h4 {
  font-size: 1.1rem;
  margin-bottom: 4px;
  font-family: var(--font-primary);
}

.contact-text p {
  color: var(--color-text-muted);
  font-size: 0.95rem;
  margin: 0;
}

.contact-form {
  background: var(--color-bg-secondary);
  padding: var(--spacing-xl);
  border-radius: var(--border-radius-lg);
  box-shadow: var(--shadow-md);
}

.form-group {
  margin-bottom: var(--spacing-md);
}

.form-group label {
  display: block;
  margin-bottom: var(--spacing-xs);
  font-weight: 500;
  color: var(--color-text);
}

.form-group input,
.form-group textarea {
  width: 100%;
  padding: var(--spacing-sm);
  background: var(--color-bg);
  border: 1px solid rgba(212, 175, 55, 0.2);
  border-radius: var(--border-radius-md);
  color: var(--color-text);
  font-family: inherit;
  font-size: 1rem;
  transition: border-color var(--transition-fast);
  min-height: 48px;
}

.form-group input:focus,
.form-group textarea:focus {
  outline: none;
  border-color: var(--color-gold-primary);
  box-shadow: 0 0 0 3px rgba(212, 175, 55, 0.1);
}

.form-group textarea {
  min-height: 150px;
  resize: vertical;
}

.form-submit {
  width: 100%;
  margin-top: var(--spacing-md);
}

/* Social Links */
.social-links {
  display: flex;
  gap: var(--spacing-md);
  margin-top: var(--spacing-lg);
}

.social-link {
  width: 45px;
  height: 45px;
  background: rgba(212, 175, 55, 0.1);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--color-gold-primary);
  font-size: 1.2rem;
  transition: all var(--transition-normal);
}

.social-link:hover {
  background: var(--color-gold-primary);
  color: var(--color-bg);
  transform: translateY(-3px);
}

/* Footer */
footer {
  background: var(--color-bg-secondary);
  padding: var(--spacing-xl) 0;
  text-align: center;
  border-top: 1px solid rgba(212, 175, 55, 0.1);
}

.footer-content {
  max-width: 600px;
  margin: 0 auto;
}

.footer-logo {
  font-size: 1.5rem;
  font-weight: 700;
  color: var(--color-gold-primary);
  margin-bottom: var(--spacing-md);
}

.footer-text {
  color: var(--color-text-muted);
  font-size: 0.95rem;
  margin-bottom: var(--spacing-md);
}

.footer-links {
  display: flex;
  justify-content: center;
  gap: var(--spacing-lg);
  margin-bottom: var(--spacing-md);
  flex-wrap: wrap;
}

.footer-links a {
  color: var(--color-text);
  font-size: 0.95rem;
}

.footer-links a:hover {
  color: var(--color-gold-primary);
}

.copyright {
  color: var(--color-text-muted);
  font-size: 0.85rem;
}

/* Navbar Styles */
.navbar {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  padding: var(--spacing-md) 0;
  z-index: 1000;
  transition: all var(--transition-normal);
  background: transparent;
}

.navbar.scrolled {
  background: rgba(10, 10, 15, 0.95);
  padding: var(--spacing-sm) 0;
  box-shadow: var(--shadow-md);
  backdrop-filter: blur(10px);
}

.nav-container {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.nav-logo {
  font-size: 1.5rem;
  font-weight: 700;
  color: var(--color-gold-primary);
  text-decoration: none;
}

.nav-menu {
  display: flex;
  list-style: none;
  gap: var(--spacing-lg);
  margin: 0;
  padding: 0;
}

.nav-menu a {
  color: var(--color-text);
  text-decoration: none;
  font-weight: 500;
  transition: color var(--transition-fast);
  position: relative;
  padding: var(--spacing-xs) 0;
}

.nav-menu a:hover,
.nav-menu a.active {
  color: var(--color-gold-primary);
}

.nav-menu a::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 0;
  height: 2px;
  background: var(--color-gold-primary);
  transition: width var(--transition-normal);
}

.nav-menu a:hover::after,
.nav-menu a.active::after {
  width: 100%;
}

.nav-toggle {
  display: none;
  background: none;
  border: none;
  cursor: pointer;
  padding: var(--spacing-xs);
}

.hamburger {
  display: block;
  width: 25px;
  height: 3px;
  background: var(--color-gold-primary);
  position: relative;
  transition: all var(--transition-normal);
}

.hamburger::before,
.hamburger::after {
  content: '';
  position: absolute;
  width: 25px;
  height: 3px;
  background: var(--color-gold-primary);
  transition: all var(--transition-normal);
}

.hamburger::before {
  top: -8px;
}

.hamburger::after {
  top: 8px;
}

.nav-toggle.active .hamburger {
  background: transparent;
}

.nav-toggle.active .hamburger::before {
  top: 0;
  transform: rotate(45deg);
}

.nav-toggle.active .hamburger::after {
  top: 0;
  transform: rotate(-45deg);
}

/* Back to Top Button */
.back-to-top {
  position: fixed;
  bottom: 30px;
  right: 30px;
  width: 50px;
  height: 50px;
  background: var(--color-gold-primary);
  color: var(--color-bg);
  border: none;
  border-radius: 50%;
  font-size: 1.5rem;
  cursor: pointer;
  opacity: 0;
  visibility: hidden;
  transition: all var(--transition-normal);
  z-index: 999;
  box-shadow: var(--shadow-gold);
  display: flex;
  align-items: center;
  justify-content: center;
}

.back-to-top.visible {
  opacity: 1;
  visibility: visible;
}

.back-to-top:hover {
  transform: translateY(-5px);
  box-shadow: 0 10px 30px rgba(212, 175, 55, 0.6);
}

/* Loading Screen */
.loading-screen {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: var(--color-bg);
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 9999;
  transition: opacity var(--transition-slow);
}

.loading-screen.loaded {
  opacity: 0;
  pointer-events: none;
}

.loader {
  text-align: center;
}

.loader-circle {
  width: 50px;
  height: 50px;
  border: 3px solid var(--color-gold-primary);
  border-top-color: transparent;
  border-radius: 50%;
  animation: spin 1s linear infinite;
  margin: 0 auto var(--spacing-md);
}

.loader-text {
  color: var(--color-gold-primary);
  font-size: 1.2rem;
  letter-spacing: 2px;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

/* Animations */
.animate-on-scroll {
  opacity: 0;
  transform: translateY(30px);
  transition: all 0.6s ease-out;
}

.animate-on-scroll.animate-visible {
  opacity: 1;
  transform: translateY(0);
}

@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.animate-fade-in {
  animation: fadeIn 0.6s ease-out forwards;
  opacity: 0;
}

/* Custom Cursor */
.custom-cursor {
  position: fixed;
  width: 20px;
  height: 20px;
  border: 2px solid var(--color-gold-primary);
  border-radius: 50%;
  pointer-events: none;
  z-index: 9999;
  transform: translate(-50%, -50%);
  transition: all 0.2s ease;
  mix-blend-mode: difference;
}

.custom-cursor.hover {
  width: 40px;
  height: 40px;
  background: rgba(212, 175, 55, 0.2);
}

/* Ripple Effect */
.btn {
  position: relative;
  overflow: hidden;
}

.ripple {
  position: absolute;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.4);
  transform: scale(0);
  animation: ripple-animation 0.6s ease-out;
  pointer-events: none;
}

@keyframes ripple-animation {
  to {
    transform: scale(4);
    opacity: 0;
  }
}

/* ============================================
   RESPONSIVE BREAKPOINTS
   ============================================ */

/* Mobile Devices (up to 480px) */
@media (max-width: 480px) {
  html {
    font-size: 14px;
  }

  .container {
    padding: 0 var(--spacing-sm);
  }

  section {
    padding: var(--spacing-xl) 0;
  }

  .hero-content {
    padding: var(--spacing-md);
  }

  .hero-buttons {
    flex-direction: column;
    align-items: center;
  }

  .hero-buttons .btn {
    width: 100%;
    max-width: 280px;
  }

  .projects-grid,
  .awards-grid {
    grid-template-columns: 1fr;
    gap: var(--spacing-md);
  }

  .contact-content {
    grid-template-columns: 1fr;
    gap: var(--spacing-xl);
  }

  .contact-form {
    padding: var(--spacing-lg);
  }

  .social-links {
    justify-content: center;
  }

  .footer-links {
    gap: var(--spacing-md);
  }

  .back-to-top {
    bottom: 20px;
    right: 20px;
    width: 45px;
    height: 45px;
    font-size: 1.2rem;
  }

  .nav-menu {
    position: fixed;
    top: 0;
    right: -100%;
    width: 80%;
    max-width: 300px;
    height: 100vh;
    background: rgba(10, 10, 15, 0.98);
    flex-direction: column;
    justify-content: center;
    align-items: center;
    gap: var(--spacing-lg);
    transition: right var(--transition-normal);
    backdrop-filter: blur(10px);
  }

  .nav-menu.active {
    right: 0;
  }

  .nav-menu a {
    font-size: 1.3rem;
  }

  .nav-toggle {
    display: block;
  }

  .project-image {
    height: 180px;
  }

  .award-icon {
    font-size: 2.5rem;
  }
}

/* Tablet Devices (481px to 768px) */
@media (min-width: 481px) and (max-width: 768px) {
  html {
    font-size: 15px;
  }

  .container {
    padding: 0 var(--spacing-md);
  }

  section {
    padding: var(--spacing-xl) 0;
  }

  .projects-grid,
  .awards-grid {
    grid-template-columns: repeat(2, 1fr);
    gap: var(--spacing-md);
  }

  .contact-content {
    grid-template-columns: 1fr;
    gap: var(--spacing-xl);
  }

  .contact-form {
    padding: var(--spacing-lg);
  }

  .nav-menu {
    position: fixed;
    top: 0;
    right: -100%;
    width: 70%;
    height: 100vh;
    background: rgba(10, 10, 15, 0.98);
    flex-direction: column;
    justify-content: center;
    align-items: center;
    gap: var(--spacing-lg);
    transition: right var(--transition-normal);
    backdrop-filter: blur(10px);
  }

  .nav-menu.active {
    right: 0;
  }

  .nav-menu a {
    font-size: 1.2rem;
  }

  .nav-toggle {
    display: block;
  }

  .back-to-top {
    bottom: 20px;
    right: 20px;
    width: 45px;
    height: 45px;
  }
}

/* Small Desktop (769px to 1024px) */
@media (min-width: 769px) and (max-width: 1024px) {
  .container {
    max-width: 960px;
  }

  .projects-grid,
  .awards-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .contact-content {
    gap: var(--spacing-xl);
  }
}

/* Large Desktop (1025px to 1440px) */
@media (min-width: 1025px) and (max-width: 1440px) {
  .container {
    max-width: 1200px;
  }

  .projects-grid,
  .awards-grid {
    grid-template-columns: repeat(3, 1fr);
  }
}

/* Extra Large Desktop (1441px+) */
@media (min-width: 1441px) {
  .container {
    max-width: 1400px;
  }

  html {
    font-size: 18px;
  }

  .projects-grid,
  .awards-grid {
    grid-template-columns: repeat(3, 1fr);
    gap: var(--spacing-xl);
  }
}

/* Landscape Orientation */
@media (max-height: 500px) and (orientation: landscape) {
  .hero {
    min-height: auto;
    padding: var(--spacing-xl) 0;
  }

  .hero-title {
    font-size: clamp(2rem, 5vw, 3.5rem);
  }

  .hero-subtitle {
    font-size: clamp(1rem, 2vw, 1.2rem);
  }
}

/* Touch Devices */
@media (pointer: coarse) {
  .btn:hover {
    transform: none;
  }

  .project-card:hover,
  .award-card:hover {
    transform: none;
  }

  .custom-cursor {
    display: none;
  }

  .nav-menu a {
    min-height: 48px;
    display: flex;
    align-items: center;
  }

  .social-link {
    min-width: 48px;
    min-height: 48px;
  }
}

/* Reduced Motion */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }

  .animate-on-scroll {
    opacity: 1;
    transform: none;
  }

  .scroll-indicator {
    display: none;
  }
}

/* High Contrast Mode */
@media (prefers-contrast: high) {
  :root {
    --color-text: #ffffff;
    --color-text-muted: #cccccc;
    --color-gold-primary: #ffd700;
  }

  .project-card,
  .award-card,
  .contact-form {
    border: 2px solid var(--color-gold-primary);
  }
}

/* Dark Mode (default) */
@media (prefers-color-scheme: dark) {
  :root {
    --color-bg: #0a0a0f;
    --color-bg-secondary: #12121a;
    --color-text: #e0e0e0;
    --color-text-muted: #a0a0a0;
  }
}

/* Light Mode Support */
@media (prefers-color-scheme: light) {
  :root {
    --color-bg: #ffffff;
    --color-bg-secondary: #f5f5f5;
    --color-text: #1a1a1a;
    --color-text-muted: #666666;
  }

  .navbar.scrolled {
    background: rgba(255, 255, 255, 0.95);
  }

  .project-card,
  .award-card,
  .contact-form {
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.1);
  }
}

/* Print Styles */
@media print {
  .navbar,
  .back-to-top,
  .scroll-indicator,
  .loading-screen,
  .custom-cursor,
  .social-links,
  .contact-form {
    display: none !important;
  }

  body {
    background: white;
    color: black;
    font-size: 12pt;
  }

  section {
    page-break-inside: avoid;
  }

  a {
    color: black;
    text-decoration: underline;
  }

  .project-card,
  .award-card {
    break-inside: avoid;
    box-shadow: none;
    border: 1px solid #ccc;
  }
}

/* Accessibility - Focus States */
@media (prefers-reduced-motion: no-preference) {
  a:focus,
  button:focus,
  input:focus,
  textarea:focus {
    outline: 2px solid var(--color-gold-primary);
    outline-offset: 2px;
  }

  a:focus:not(:focus-visible),
  button:focus:not(:focus-visible) {
    outline: none;
  }

  a:focus-visible,
  button:focus-visible {
    outline: 2px solid var(--color-gold-primary);
    outline-offset: 2px;
  }
}

/* Screen Reader Only */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
