const React = require('react');

class TodoList extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      items: []
    };
  }

  componentDidMount() {
    fetch('/api/todos')
      .then(response => response.json())
      .then(data => this.setState({ items: data }));
  }

  addItem = (item) => {
    const newItem = { id: Date.now(), text: item, completed: false };
    this.setState(prevState => ({
      items: [...prevState.items, newItem]
    }));
  };

  deleteItem = (id) => {
    const updatedItems = this.state.items.filter(item => item.id !== id);
    this.setState({ items: updatedItems });
  };

  toggleCompleted = (id) => {
    const updatedItems = this.state.items.map(item =>
      item.id === id ? { ...item, completed: !item.completed } : item
    );
    this.setState({ items: updatedItems });
  };

  render() {
    return (
      <div className="todo-list">
        <ul>
          {this.state.items.map(item => (
            <li key={item.id}>
              <input type="checkbox" checked={item.completed} onChange={() => this.toggleCompleted(item.id)} />
              <span style={{ text-decoration: item.completed ? 'line-through' : '' }}>{item.text}</span>
              <button onClick={() => this.deleteItem(item.id)}>Delete</button>
            </li>
          ))}
        </ul>
        <form onSubmit={event => {
          event.preventDefault();
          const newItem = document.querySelector('#new-item').value;
          if (newItem.trim() !== '') {
            this.addItem(newItem);
            document.getElementById('new-item').value = '';
          }
        }}>
          <input type="text" id="new-item" placeholder="Add a new item" />
          <button type="submit">Add</button>
        </form>
      </div>
    );
  }
}

module.exports = TodoList;

